const SHARE_SITE = 'https://st-reborn.de';

// shareTriggerHTML is the dashed, accent-tinted button placed under the donate
// buttons: the escalation from "you like it" (donate) to "you love it" (share).
// Not permanent - it just opens the modal.
export function shareTriggerHTML() {
  return `<button class="share-trigger" id="shareTrigger" type="button">
    <span class="share-heart">&#9829;</span>${escapeHtml(t('share.trigger'))}</button>`;
}

// shareModalHTML is the roomy dialog with one tile per platform. Each tile is
// clickable (opens the browser share on this PC) AND carries a QR that opens the
// same platform's post on a phone, so a visitor logged in on their phone just
// taps Send.
export function shareModalHTML() {
  const tiles = SHARE_PLATFORMS.map(p => `
    <a class="share-tile share-${p.key}" href="#" data-url="${escapeAttr(p.url)}" style="--brand:${p.color}">
      <span class="share-ic">${SHARE_ICONS[p.key] || ''}</span>
      <span class="share-name">${escapeHtml(p.name)}</span>
      <span class="share-qr">${p.qr}</span>
      <span class="share-scan">${escapeHtml(t('share.scan'))}</span>
    </a>`).join('');
  return `<div class="modal hidden" id="shareModal">
    <div class="modal-content share-modal">
      <h3 id="shareTitle">${escapeHtml(t('share.head'))}</h3>
      <p class="modal-sub" id="shareSay">${escapeHtml(t('share.say'))}</p>
      <div class="share-tiles">${tiles}</div>
      <div class="share-foot">
        <button class="btn" id="shareEmail" type="button">&#9993; ${escapeHtml(t('share.email'))}</button>
        <button class="btn" id="shareCopy" type="button">&#128203; ${escapeHtml(t('share.copy'))}</button>
        <button class="btn" id="shareClose" type="button">${escapeHtml(t('common.close'))}</button>
      </div>
    </div>
  </div>`;
}

// wireShareModal wires the tiles, copy-link and close/backdrop once the modal is
// in the DOM. Idempotent-safe: called after the app HTML renders.
export function wireShareModal() {
  const modal = document.getElementById('shareModal');
  if (!modal) return;
  modal.querySelectorAll('.share-tile[data-url]').forEach(a => {
    a.onclick = (e) => { e.preventDefault(); BrowserOpenURL(a.dataset.url); };
  });
  // Open the user's mail app with a ready-to-send message, so sharing by email
  // is one click instead of "copy the link, now go write an email yourself".
  const email = document.getElementById('shareEmail');
  if (email) email.onclick = () => {
    const url = 'mailto:?subject=' + encodeURIComponent(t('share.emailSubject')) +
      '&body=' + encodeURIComponent(t('share.emailBody'));
    BrowserOpenURL(url);
  };
  const copy = document.getElementById('shareCopy');
  if (copy) copy.onclick = async () => {
    try { await navigator.clipboard.writeText(SHARE_SITE); } catch (e) {}
    const was = copy.innerHTML;
    copy.textContent = t('share.copied');
    setTimeout(() => { copy.innerHTML = was; }, 1500);
  };
  const close = document.getElementById('shareClose');
  if (close) close.onclick = closeShareModal;
  modal.onclick = (e) => { if (e.target === modal) closeShareModal(); };
}

export function openShareModal() {
  const m = document.getElementById('shareModal');
  if (m) m.classList.remove('hidden');
}
export function closeShareModal() {
  const m = document.getElementById('shareModal');
  if (m) m.classList.add('hidden');
}
